INSERT INTO "public"."culture_dialect" ("id", "word", "meaning", "type", "example", "category", "is_popular", "created_at") VALUES ('17bad546-ad3a-415b-ab1b-2d20ef3be16a', 'Gobel', 'Erkek çocuk, genç delikanlı.', 'isim', 'Bizim gobel yine yaramazlık yapmış.', 'Akrabalık', 'true', '2026-01-04 11:07:30.096695+00'), ('17d8ec1f-6cad-446f-8330-bc77eec0162b', 'Culfuk', 'Hindi.', 'isim', 'Akşama culfuk pişireceğiz.', 'Mutfak', 'false', '2026-01-04 11:07:30.096695+00'), ('2f8e5915-585a-482b-a284-06fb2f4943f6', 'Zebellah', 'İri yarı, korkutucu görünümlü kimse.', 'sıfat', 'Kapıda zebellah gibi adamlar vardı.', 'Genel', 'false', '2026-01-04 11:07:30.096695+00'), ('6d3fd9ca-e388-4a10-9a7a-4e2a9a0ec746', 'deneme', 'kooekfore', 'isim', 'merhaba deneme', 'Genel', 'false', '2026-01-06 16:27:37.991625+00'), ('71dc89da-5028-42bd-a5f0-6b075b7de984', 'Gadasını Aldığım', 'Derdin bana gelsin anlamında sevgi sözü.', 'ünlem', 'Aman gadasını aldığım üzülme sen.', 'Akrabalık', 'true', '2026-01-04 11:07:30.096695+00'), ('aed085e5-5588-4a38-b90e-8dce1d771e05', 'Ellaham', 'Galiba, sanırsam, herhalde anlamında ihtimal bildirme.', 'zarf', 'Ellaham yağmur yağacak.', 'Genel', 'true', '2026-01-04 11:07:30.096695+00'), ('e045cbb9-c668-4f72-8c8c-b17c80456200', 'Nörüyon', 'Ne yapıyorsun, nasılsın anlamında genel bir hal hatır sorma kalıbı.', 'ünlem', 'Nörüyon ortağım, keyifler nasıl?', 'Genel', 'true', '2026-01-04 11:07:30.096695+00');